const t={maxFlow:{intro:{t:0,b:{t:2,i:[{t:3}],s:"Определите максимальный объёмный поток (mm³/s), который способен выдержать ваш хотенд — постепенно повышая поток и наблюдая за нагрузкой StallGuard экструдера до момента проскальзывания шестерни. Сначала посмотрите план; живой тест нагревает и экструдирует, поэтому подготовьте принтер перед запуском."}},help:{guide:{t:0,b:{t:2,i:[{t:3}],s:"Справка"}},guideTitle:{t:0,b:{t:2,i:[{t:3}],s:"О тесте Max-Flow"}},close:{t:0,b:{t:2,i:[{t:3}],s:"Закрыть"}},howToRead:{t:0,b:{t:2,i:[{t:3}],s:"Как пользоваться"}},steps:[{t:0,b:{t:2,i:[{t:3}],s:"Задайте температуру теста и диаметр филамента (выберите хотенд для предзаполнения)."}},{t:0,b:{t:2,i:[{t:3}],s:"Посмотрите план — он показывает каждый шаг потока и сколько филамента продавливается."}},{t:0,b:{t:2,i:[{t:3}],s:"Отметьте контрольный список безопасности, затем запустите живой тест (нагрев + экструзия)."}},{t:0,b:{t:2,i:[{t:3}],s:"Считайте максимальный устойчивый поток и скопируйте предложенное значение для слайсера."}}],topics:{howItWorks:{title:{t:0,b:{t:2,i:[{t:3}],s:"Как работает тест"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Экструдер продавливает филамент с равномерно возрастающим объёмным потоком. Пока зубчатая шестерня надёжно держит филамент, показания нагрузки StallGuard остаются стабильными; как только начинается проскальзывание, показания начинают скакать. Максимальный поток, достигнутый до этого скачка, и есть ваш устойчивый максимальный поток. Нарастание прекращается, как только обнаружено проскальзывание, поэтому филамент не перетирается после первого проскальзывания."}}},stallguard:{title:{t:0,b:{t:2,i:[{t:3}],s:"Обнаружение проскальзывания через StallGuard"}},body:{t:0,b:{t:2,i:[{t:3}],s:"StallGuard — это функция драйвера TMC, которая сообщает о нагрузке мотора. Этот тест опрашивает её многократно на каждом шаге потока и ищет резкий рост разброса (IQR) или вариации (CV) — признак потери сцепления шестерни. Пороги берутся из профиля для конкретного драйвера. Примечание: на экструдере с TMC2209 используется экспериментальный путь SG4, поэтому считайте первый запуск калибровочным."}}},safety:{title:{t:0,b:{t:2,i:[{t:3}],s:"Безопасность"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Это горячий тест с движением, который намеренно доводит экструдер до проскальзывания. Загрузите филамент, убедитесь, что сопло свободно (над столом или зоной для отходов), и оставайтесь рядом. Запуск отклоняется, пока принтер печатает, а нагреватель всегда выключается по завершении."}}},slicer:{title:{t:0,b:{t:2,i:[{t:3}],s:"Использование результата"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Введите предложенное значение в параметр «max volumetric speed» вашего слайсера (для каждого филамента). Консервативное значение (80% от измеренного максимума) — это безопасный повседневный предел; сбалансированное значение (90%) немного агрессивнее. Более высокие температуры хотенда обычно повышают достижимый поток."}}},glossary:{title:{t:0,b:{t:2,i:[{t:3}],s:"Глоссарий"}},body:{t:0,b:{static:"",t:2,i:[]}}}},glossary:{flow:{term:{t:0,b:{t:2,i:[{t:3}],s:"Объёмный поток"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Сколько пластика хотенд расплавляет в секунду (mm³/s) — реальный предел скорости для быстрой печати."}}},stallguard:{term:{t:0,b:{t:2,i:[{t:3}],s:"StallGuard"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Сигнал драйвера TMC, сообщающий о механической нагрузке мотора, здесь используется для определения проскальзывания экструдера."}}},slip:{term:{t:0,b:{t:2,i:[{t:3}],s:"Проскальзывание"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Когда шестерня экструдера больше не может достаточно быстро удерживать филамент и проскакивает — это потолок потока."}}},meltzone:{term:{t:0,b:{t:2,i:[{t:3}],s:"Зона плавления"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Нагреваемая длина хотенда; более длинная зона плавления (например, Volcano) поддерживает более высокий поток."}}}}},params:{title:{t:0,b:{t:2,i:[{t:3}],s:"Параметры теста"}},temperature:{t:0,b:{t:2,i:[{t:3}],s:"Температура (°C)"}},filamentDiameter:{t:0,b:{t:2,i:[{t:3}],s:"Ø филамента (mm)"}},hotend:{t:0,b:{t:2,i:[{t:3}],s:"Хотенд (необязательно)"}},hotendNone:{t:0,b:{t:2,i:[{t:3}],s:"— нет —"}},hotendHint:{t:0,b:{t:2,i:[{t:3,v:"Ожидается ~"},{t:4,k:"flow"},{t:3,v:" mm³/s"}]}},startFlow:{t:0,b:{t:2,i:[{t:3}],s:"Начальный поток (mm³/s)"}},endFlow:{t:0,b:{t:2,i:[{t:3}],s:"Конечный поток (mm³/s)"}},stepFlow:{t:0,b:{t:2,i:[{t:3}],s:"Шаг (mm³/s)"}},samples:{t:0,b:{t:2,i:[{t:3}],s:"Замеров / шаг"}},extrudePerStep:{t:0,b:{t:2,i:[{t:3}],s:"Экструзия / шаг (mm)"}},driver:{t:0,b:{t:2,i:[{t:3}],s:"Драйвер экструдера"}},driverDetected:{t:0,b:{t:2,i:[{t:3}],s:"определён с принтера"}},autoStealthchop:{t:0,b:{t:2,i:[{t:3}],s:"Автоматически включить StealthChop для теста"}},autoStealthchopHint:{t:0,b:{t:2,i:[{t:3}],s:"Только TMC2209/2240: временно записывает stealthchop_threshold в конфиг экструдера, чтобы StallGuard мог читать, а затем комментирует его после теста. Восстанавливает printer.cfg; перезагрузка прошивки в оба конца."}}},plan:{button:{t:0,b:{t:2,i:[{t:3}],s:"Посмотреть план"}},title:{t:0,b:{t:2,i:[{t:3}],s:"Запланированное нарастание"}},stepCount:{t:0,b:{t:2,i:[{t:4,k:"count"},{t:3,v:" шагов"}]}},totalExtrude:{t:0,b:{t:2,i:[{t:4,k:"mm"},{t:3,v:" mm филамента"}]}},sgField:{t:0,b:{t:2,i:[{t:3,v:"Поле StallGuard: "},{t:4,k:"field"}]}},sgFieldUnknown:{t:0,b:{t:2,i:[{t:3}],s:"Для этого драйвера неизвестно поле StallGuard"}},flowHead:{t:0,b:{t:2,i:[{t:3}],s:"Поток (mm³/s)"}},feedrateHead:{t:0,b:{t:2,i:[{t:3}],s:"Подача (mm/min)"}},warning:{t:0,b:{t:2,i:[{t:3}],s:"Живой тест нагревает хотенд и экструдирует филамент, намеренно доводя до проскальзывания. Это только предпросмотр — ничего пока не запускается."}}},safety:{title:{t:0,b:{t:2,i:[{t:3}],s:"Перед запуском — контрольный список безопасности"}},items:[{t:0,b:{t:2,i:[{t:3}],s:"Филамент загружен и подаётся свободно."}},{t:0,b:{t:2,i:[{t:3}],s:"Сопло свободно — над столом или ёмкостью для отходов, а не в воздух на детали."}},{t:0,b:{t:2,i:[{t:3}],s:"Я принимаю, что часть филамента будет намеренно перетёрта/проскользнёт."}},{t:0,b:{t:2,i:[{t:3}],s:"Я буду находиться рядом с принтером весь тест."}}],ack:{t:0,b:{t:2,i:[{t:3}],s:"Я выполнил всё вышеперечисленное, и принтер готов"}},note:{t:0,b:{t:2,i:[{t:3}],s:"Запуск отклоняется во время печати; нагреватель автоматически выключается по завершении."}}},run:{button:{t:0,b:{t:2,i:[{t:3}],s:"Запустить живой тест"}},running:{t:0,b:{t:2,i:[{t:3}],s:"Выполняется… (нагрев + экструзия)"}},confirmTitle:{t:0,b:{t:2,i:[{t:3}],s:"Запустить живой тест максимального потока?"}},confirmBody:{t:0,b:{t:2,i:[{t:3,v:"Это нагреет хотенд до "},{t:4,k:"temp"},{t:3,v:" °C и выдавит до "},{t:4,k:"mm"},{t:3,v:" mm филамента, наращивая поток до проскальзывания экструдера."}]}},confirm:{t:0,b:{t:2,i:[{t:3}],s:"Запустить сейчас"}},cancel:{t:0,b:{t:2,i:[{t:3}],s:"Отмена"}},busy:{t:0,b:{t:2,i:[{t:3}],s:"Отклонено: принтер занят (печатает или на паузе). Повторите, когда он будет в простое."}},error:{t:0,b:{t:2,i:[{t:3}],s:"Тест не удался."}},noSg:{t:0,b:{t:2,i:[{t:3}],s:"Не было получено ни одного замера StallGuard — результат проскальзывания может быть ненадёжным. Вероятно, для этой модели нужно скорректировать живое поле SG драйвера."}},progress:{t:0,b:{t:2,i:[{t:3,v:"Шаг "},{t:4,k:"step"},{t:3,v:"/"},{t:4,k:"total"},{t:3,v:" — "},{t:4,k:"flow"},{t:3,v:" мм³/с"}]}},starting:{t:0,b:{t:2,i:[{t:3}],s:"Нагрев / запуск…"}},abort:{t:0,b:{t:2,i:[{t:3}],s:"Прервать тест"}},cancelling:{t:0,b:{t:2,i:[{t:3}],s:"Прерывание…"}},cancelled:{t:0,b:{t:2,i:[{t:3}],s:"Тест прерван — нагреватель выключен."}},reattached:{t:0,b:{t:2,i:[{t:3}],s:"Возобновлено: результат завершился, пока страница была закрыта."}},failed:{t:0,b:{t:2,i:[{t:3}],s:"Тест макс. потока не удался."}},abortNote:{t:0,b:{t:2,i:[{t:3}],s:"Прерывание всегда выключает нагреватель."}},parkNote:{t:0,b:{t:2,i:[{t:3}],s:"Перед нагревом принтер выполняет инициализацию (если необходимо) и центрирует сопло для лучшего обзора."}},phase:{homing:{t:0,b:{t:2,i:[{t:3}],s:"Инициализация принтера…"}},centering:{t:0,b:{t:2,i:[{t:3}],s:"Центрирование сопла…"}},heating:{t:0,b:{t:2,i:[{t:3}],s:"Нагрев хотенда…"}},checking:{t:0,b:{t:2,i:[{t:3}],s:"Проверка сигнала StallGuard…"}},enabling:{t:0,b:{t:2,i:[{t:3}],s:"Включение StealthChop…"}},ramp:{t:0,b:{t:2,i:[{t:3}],s:"Наращивание потока…"}},reverting:{t:0,b:{t:2,i:[{t:3}],s:"Восстановление конфига…"}}},step:{home:{t:0,b:{t:2,i:[{t:3}],s:"Инициализация"}},center:{t:0,b:{t:2,i:[{t:3}],s:"Центрирование"}},heat:{t:0,b:{t:2,i:[{t:3}],s:"Нагрев"}},check:{t:0,b:{t:2,i:[{t:3}],s:"Проверка"}},ramp:{t:0,b:{t:2,i:[{t:3}],s:"Нарастание"}}}},result:{title:{t:0,b:{t:2,i:[{t:3}],s:"Результат"}},maxFlow:{t:0,b:{t:2,i:[{t:3}],s:"Максимальный устойчивый поток"}},slipAt:{t:0,b:{t:2,i:[{t:3,v:"Проскальзывание обнаружено при "},{t:4,k:"flow"},{t:3,v:" mm³/s"}]}},noSlip:{t:0,b:{t:2,i:[{t:3}],s:"Проскальзывания нет вплоть до максимального протестированного потока"}},reason:{t:0,b:{t:2,i:[{t:3}],s:"Подробности"}},recommendTitle:{t:0,b:{t:2,i:[{t:3}],s:"Предложенные значения для слайсера (max volumetric speed)"}},conservative:{t:0,b:{t:2,i:[{t:3}],s:"Консервативное (80%)"}},balanced:{t:0,b:{t:2,i:[{t:3}],s:"Сбалансированное (90%)"}},units:{t:0,b:{t:2,i:[{t:3}],s:"mm³/s"}},fromBefore:{t:0,b:{t:2,i:[{t:3,v:"Измерено ранее ("},{t:4,k:"at"},{t:3,v:") — запустите снова для свежих цифр."}]}},unreliableTitle:{t:0,b:{t:2,i:[{t:3}],s:"Ненадёжный — сигнал StallGuard не получен"}},unmeasured:{t:0,b:{t:2,i:[{t:3}],s:"достигнут, не подтверждён"}}},states:{loadingHotends:{t:0,b:{t:2,i:[{t:3}],s:"Загрузка хотендов…"}}},camera:{title:{t:0,b:{t:2,i:[{t:3}],s:"Живая камера"}},live:{t:0,b:{t:2,i:[{t:3}],s:"ТРАНСЛЯЦИЯ"}},error:{t:0,b:{t:2,i:[{t:3}],s:"Камера недоступна."}},willShow:{t:0,b:{t:2,i:[{t:3}],s:"Во время теста трансляция с камеры будет показывать сопло."}},minimize:{t:0,b:{t:2,i:[{t:3}],s:"Свернуть"}},maximize:{t:0,b:{t:2,i:[{t:3}],s:"Развернуть"}},enlarge:{t:0,b:{t:2,i:[{t:3}],s:"Увеличить"}},shrink:{t:0,b:{t:2,i:[{t:3}],s:"Уменьшить"}}}}};export{t as default};
